// Product interface (Strategy)
interface PaymentProcessor {
    void validate(String details);
    String charge(double amount);
    void refund(String txnId);
    String getName();
}

// Concrete Products
class CreditCardProcessor implements PaymentProcessor {
    private String merchantId;
    public CreditCardProcessor(String merchantId) { this.merchantId = merchantId; }
    public void validate(String details) {
        System.out.println("  Luhn check on card: " + details.substring(details.length() - 4));
    }
    public String charge(double amount) {
        String txnId = "CC-" + System.currentTimeMillis();
        System.out.println("  Charged $" + amount + " via card network (merchant: " + merchantId + ")");
        return txnId;
    }
    public void refund(String txnId) {
        System.out.println("  Refunded " + txnId + " via card network");
    }
    public String getName() { return "Credit Card"; }
}

class UPIProcessor implements PaymentProcessor {
    private String pspId;
    public UPIProcessor(String pspId) { this.pspId = pspId; }
    public void validate(String details) {
        System.out.println("  VPA format check: " + details);
    }
    public String charge(double amount) {
        String txnId = "UPI-" + System.currentTimeMillis();
        System.out.println("  Charged Rs." + amount + " via NPCI (PSP: " + pspId + ")");
        return txnId;
    }
    public void refund(String txnId) {
        System.out.println("  UPI reversal for " + txnId);
    }
    public String getName() { return "UPI"; }
}

// Abstract Service with Factory Method
abstract class PaymentService {
    abstract PaymentProcessor createProcessor();

    // Template: shared orchestration
    public void processPayment(String details, double amount) {
        PaymentProcessor processor = createProcessor();
        System.out.println("Processing " + processor.getName() + " payment...");
        processor.validate(details);
        String txnId = processor.charge(amount);
        System.out.println("  Transaction ID: " + txnId);
        log(processor.getName(), amount, txnId);
    }

    private void log(String method, double amount, String txnId) {
        System.out.println("  [LOG] " + method + " | $" + amount + " | " + txnId);
    }
}

// Concrete Services -- each owns private creation logic
class CreditCardPaymentService extends PaymentService {
    PaymentProcessor createProcessor() {
        String merchantId = "WMT-" + System.getenv().getOrDefault("MERCHANT_ID", "DEFAULT");
        return new CreditCardProcessor(merchantId);
    }
}

class UPIPaymentService extends PaymentService {
    PaymentProcessor createProcessor() {
        String pspId = "PSP-WALMART-IN";
        System.out.println("  Loading UPI config (PSP: " + pspId + ")");
        return new UPIProcessor(pspId);
    }
}

// Simple Factory to select the right service
class PaymentServiceFactory {
    public static PaymentService create(String type) {
        return switch (type.toUpperCase()) {
            case "CREDIT_CARD" -> new CreditCardPaymentService();
            case "UPI"         -> new UPIPaymentService();
            default -> throw new IllegalArgumentException("Unknown: " + type);
        };
    }
}

public class Main {
    public static void main(String[] args) {
        // User selects UPI
        String userChoice = "UPI";
        PaymentService service = PaymentServiceFactory.create(userChoice);
        service.processPayment("ravi@upi", 999.0);

        System.out.println();

        // User selects Credit Card
        userChoice = "CREDIT_CARD";
        service = PaymentServiceFactory.create(userChoice);
        service.processPayment("4111111111111234", 2499.0);
    }
}

