#include <iostream>
#include <string>
#include <memory>
#include <stdexcept>
using namespace std;

class PaymentProcessor {
public:
    virtual ~PaymentProcessor() = default;
    virtual void validate(const string& details) = 0;
    virtual string charge(double amount) = 0;
    virtual string getName() const = 0;
};

class CreditCardProcessor : public PaymentProcessor {
    string merchantId;
public:
    explicit CreditCardProcessor(string mid) : merchantId(move(mid)) {}
    void validate(const string& details) override {
        cout << "  Luhn check: ****" << details.substr(details.length() - 4) << endl;
    }
    string charge(double amount) override {
        cout << "  Charged $" << amount << " via card network" << endl;
        return "CC-TXN-001";
    }
    string getName() const override { return "Credit Card"; }
};

class UPIProcessor : public PaymentProcessor {
    string pspId;
public:
    explicit UPIProcessor(string psp) : pspId(move(psp)) {}
    void validate(const string& details) override {
        cout << "  VPA check: " << details << endl;
    }
    string charge(double amount) override {
        cout << "  Charged Rs." << amount << " via NPCI" << endl;
        return "UPI-TXN-001";
    }
    string getName() const override { return "UPI"; }
};

class PaymentService {
public:
    virtual ~PaymentService() = default;
    virtual unique_ptr<PaymentProcessor> createProcessor() = 0;

    void processPayment(const string& details, double amount) {
        auto processor = createProcessor();
        cout << "Processing " << processor->getName() << "..." << endl;
        processor->validate(details);
        string txnId = processor->charge(amount);
        cout << "  TXN: " << txnId << endl;
    }
};

class CreditCardPaymentService : public PaymentService {
public:
    unique_ptr<PaymentProcessor> createProcessor() override {
        return make_unique<CreditCardProcessor>("WMT-DEFAULT");
    }
};

class UPIPaymentService : public PaymentService {
public:
    unique_ptr<PaymentProcessor> createProcessor() override {
        cout << "  Loading UPI config..." << endl;
        return make_unique<UPIProcessor>("PSP-WALMART-IN");
    }
};

class PaymentServiceFactory {
public:
    static unique_ptr<PaymentService> create(const string& type) {
        if (type == "UPI") return make_unique<UPIPaymentService>();
        if (type == "CREDIT_CARD") return make_unique<CreditCardPaymentService>();
        throw invalid_argument("Unknown: " + type);
    }
};

int main() {
    auto service = PaymentServiceFactory::create("UPI");
    service->processPayment("ravi@upi", 999.0);

    cout << endl;

    service = PaymentServiceFactory::create("CREDIT_CARD");
    service->processPayment("4111111111111234", 2499.0);

    return 0;
